-- Table: cfiles
CREATE TABLE `cfiles` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `file_no` TEXT NOT NULL UNIQUE, `title` TEXT NOT NULL, `file_type` TEXT, `status` TEXT DEFAULT 'Active', `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);

-- Table: complaint_approvals
CREATE TABLE `complaint_approvals` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `complaint_id` INTEGER NOT NULL REFERENCES `complaints` (`id`) ON DELETE NO ACTION ON UPDATE CASCADE, `approved_by` TEXT, `approval_type` TEXT, `approval_status` TEXT, `notes` TEXT, `approval_date` DATETIME NOT NULL);

-- Table: complaint_categories
CREATE TABLE `complaint_categories` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `name` TEXT NOT NULL UNIQUE, `description` TEXT, `created_at` DATETIME NOT NULL);

-- Table: complaints
CREATE TABLE `complaints` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `complaint_no` TEXT NOT NULL UNIQUE, `mc_id` INTEGER REFERENCES `management_corporations` (`id`) ON DELETE SET NULL ON UPDATE CASCADE, `category_id` INTEGER REFERENCES `complaint_categories` (`id`) ON DELETE SET NULL ON UPDATE CASCADE, `complainant_name` TEXT NOT NULL, `complainant_email` TEXT, `complainant_phone` TEXT, `complaint_date` TEXT NOT NULL, `subject` TEXT NOT NULL, `description` TEXT, `status` TEXT DEFAULT 'Pending', `priority` TEXT DEFAULT 'Normal', `days_pending` INTEGER DEFAULT 0, `assigned_to_dgm` TEXT, `dgm_assigned_date` TEXT, `dgm_approval_status` TEXT, `dgm_notes` TEXT, `legal_officer_assigned` TEXT, `legal_officer_date` TEXT, `legal_officer_notes` TEXT, `resolution_date` TEXT, `resolution_notes` TEXT, `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);

-- Table: composers
CREATE TABLE `composers` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `name` TEXT NOT NULL, `era` TEXT, `work` TEXT, `description` TEXT, `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);

-- Table: management_corporations
