-- Table: mcom_records
CREATE TABLE `mcom_records` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `file_no` TEXT NOT NULL UNIQUE, `name` TEXT NOT NULL, `address` TEXT, `category` TEXT, `status` TEXT DEFAULT 'Active', `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);

